$.bK=function(){var s="Coursera Certificate",r="For Develop                                         ",q="assets/images/cours.svg",p=t.s
return A.aX(["images",A.b(["assets/images/Certificates/VMS.png","assets/images/Certificates/hmkcert.png","assets/images/Certificates/3.png","assets/images/Certificates/2.png","assets/images/Certificates/1.png","assets/images/Certificates/3k.jpg","assets/images/Certificates/1eic.jpg","assets/images/Certificates/1e.png","assets/images/Certificates/masa.png"],p),"namecompany",A.b(["VMS Certificate","Exhibition Certificate",s,s,s,"KorsatCode Certificate","EIC Certificate","Edrak Certificate","Masa Center Certificate"],p),"toptilecer",A.b(["Certificate from the Virtual Modern School","Certificate in the Project Exhibition at Al-Hamak","Matirial Components For Flutter","Build a two Screen Flutter Application","Getting Started With Flutter Development","Flutter Machine Learning","Adobe Photoshop Certificate","Programming language C#","Computer Maintenance Certificate"],p),"namecer",A.b(["Certificate of Appreciation               ","Excellence in the Graduation Project",r,r,r,r,"Photo Editor                                        ","For Develop                                        ","For Computer Basics and Programming"],p),"date",A.b(["18-OCT-2024","18-OCT-2024","17-MAR-2024","17-MAR-2024","17-MAR-2024","30-MAR-2023","29-Oct-2022","23-Jan-2022","15-JUL-2014"],p),"logo",A.b(["assets/images/vmslogo.png","assets/images/Certificates/hmk.jpg",q,q,q,"assets/images/kc.png","assets/images/EIC.jpg","assets/images/edrak.jpg","assets/images/masa.png"],p),"Link",A.b(["","","https://coursera.org/verify/QYX93QUNR9FY","https://coursera.org/verify/25BRVYQM3RXA","https://coursera.org/verify/T76ERLYVLXPC","https://www.korsatcode.com/student/certificate/6099941088","","https://programs.edraak.org/learn/verify-certificate/2da7272200444d2c804c42734decab4b/?lang=ar",""],p),"detils",A.b(["1- Team Collaboration: At the Virtual Modern School, I learned the true spirit of teamwork and how to work collaboratively with others, enhancing my ability to contribute effectively in group projects.\n2- Advanced Flutter Skills: I was able to push my Flutter development skills to their fullest potential, delivering excellent results and going beyond expectations.\n3- Web & Mobile App Success: I was responsible for developing both a web application and a mobile application, and their success is largely due to my contributions and practical expertise.\n4- Career Readiness & Effectiveness: This experience opened all paths for me, greatly increasing my effectiveness in programming, development, and other related areas, preparing me to excel in real-world projects.","1- Recognition for Innovation: My project was distinguished at the Project Exhibition in Damascus, where it was selected for its rare and unique contribution to addressing critical needs and providing significant health value to users. \n2- Valuable Health Impact: The graduation project added substantial health benefits, making it stand out in the exhibition for its potential positive impact on users' well-being.\n 3- Notable Achievement: The uniqueness and innovative nature of my project led to its special recognition, indicating its potential to make a lasting impact in its field.","1- Expanded Career Opportunities: My app development skills have increased my job prospects in the field of information technology.\n2- Practical Projects: I applied what I learned through practical projects, helping me to enhance my skills and apply knowledge effectively.\n3- Continuous Updates: I learned how to stay updated with the latest developments in Flutter, which helps me keep abreast of the latest trends in application development.","1- High Performance: I discovered ways to optimize the performance of applications using Flutter, making them faster and more responsive.\n2- Strong Support Community: I joined the Flutter developer community, which gave me the opportunity to share knowledge and receive support from other developers.\n3- Rapid Development: I took advantage of Flutter's Hot Reload feature, allowing me to see changes in real-time without needing to restart the application.","1- Learn Dart: I have acquired skills in the Dart programming language, which is the primary language used in Flutter, enhancing my ability to develop applications.\n2- Cross-Platform Application Development: I was able to create apps that run on both Android and iOS from a single codebase, saving time and effort.\n3- Attractive User Interface: I learned how to design beautiful and smooth user interfaces using Flutter tools, which helped me improve user experience.","1- Develop design skills: I gained advanced design skills in creating user-friendly applications, which helped me improve the user experience.\n2- Improved experience with learning magic: I learned how to integrate learning magic techniques into my applications, adding no additional requirements to the products I develop.\n3- Flutter Developer Community Support: I joined a vibrant community of developers, giving me the opportunity to exchange ideas and get help when needed.","1- Improved design skills: I gained advanced graphic design skills, which helped me produce high-quality artwork.\n2- Mainly photo editing: I learned how to enhance and modify photos, which affects the value of various different projects.\n3- Artistic Creations: To purchase unique and innovative designs, creating my identity as a designer.\n4- Knowing the tools available: Advanced tools and techniques cannot be used in Photoshop, which has helped me implement more invested ideas.","1- Developing desktop applications: I was able to create powerful and user-friendly desktop applications, which enhanced my experience as a developer.\n2- Improving problem-solving skills: Learning C# helped me improve my ability to analyze and effectively solve issues.\n3- Interacting with databases: I learned how to connect to databases and use them in my programs, which increased the value of the applications I developed.","1- Computer Fundamentals: I gained solid knowledge of computer basics, including operating systems, hardware, and software, which strengthened my ability to handle simple troubleshooting and maintenance.\n2- Programming Basics & Practical Application: I learned the fundamentals of programming such as variables, conditionals, and loops, along with hands-on projects that helped me connect theory with real-world practice.\n3- Passion for Programming: This certificate sparked my passion for coding and inspired me to explore programming more deeply in an enjoyable and engaging way."],p)],t.N,t.z)}()
